awk '
$2 !~ /\/(logs|backups|cache|uploads|archives)$/ && $2 != "/var/data" {
  path = $2
  n = split(path, parts, "/")
  filename = parts[n]
  if (match(filename, /\.([^.]+)$/)) {
    ext = tolower(substr(filename, RSTART+1))
  } else {
    ext = "NO_EXTENSION"
  }
  bytes[ext] += $1
}
END {
  for (ext in bytes) {
    print ext "," bytes[ext]
  }
}' /home/user/disk_inventory.txt | sort -t',' -k2,2rn

