awk '
# Skip directory entries themselves
$2 !~ /\/(logs|backups|cache|uploads|archives)$/ && $2 != "/var/data" {
  # Extract immediate subdirectory
  if (match($2, /^\/var\/data\/([^\/]+)/, arr)) {
    subdir = arr[1]
    dir_bytes[subdir] += $1
    total += $1
  }
}
END {
  for (dir in dir_bytes) {
    pct = (dir_bytes[dir] / total) * 100
    printf "%s %d %.1f%%\n", dir, dir_bytes[dir], pct
  }
}' /home/user/disk_inventory.txt | sort -k2,2rn

